const staticData = $getWorkflowStaticData('global');
const sinceToken = staticData.sinceToken || '';
const homeserver = $env.MATRIX_HOMESERVER;
const botToken = $env.MATRIX_BOT_TOKEN;
const todoRoom = $env.MATRIX_ROOM_TODO;
const qaRoom = $env.MATRIX_ROOM_QA || '';

if (!homeserver || !botToken) {
  return [];
}

// 监听的房间列表
const rooms = [todoRoom];
if (qaRoom) rooms.push(qaRoom);

const filter = JSON.stringify({
  room: {
    rooms: rooms,
    timeline: { types: ['m.room.message'], limit: 20 }
  },
  presence: { types: [] },
  account_data: { types: [] }
});

// timeout=8000: long-polling, returns immediately when new events arrive
let syncUrl = `${homeserver}/_matrix/client/v3/sync?timeout=8000&filter=${encodeURIComponent(filter)}`;
if (sinceToken) {
  syncUrl += `&since=${encodeURIComponent(sinceToken)}`;
}

return [{ json: { syncUrl, isFirstRun: !sinceToken, todoRoom, qaRoom } }];

const staticData = $getWorkflowStaticData('global');
const syncResp = $input.first().json;
const prevData = $('准备同步').first().json;
const isFirstRun = prevData.isFirstRun;
const todoRoom = prevData.todoRoom;
const qaRoom = prevData.qaRoom;

// 保存 next_batch token
if (syncResp.next_batch) {
  staticData.sinceToken = syncResp.next_batch;
}

// 首次运行或出错时跳过
if (isFirstRun || syncResp.errcode) {
  return [];
}

// 事件去重：用 staticData 记录已处理的 event_id
if (!staticData.processedEvents) {
  staticData.processedEvents = [];
}

// 房间到 bot_type 的映射
const roomMap = {};
if (todoRoom) roomMap[todoRoom] = 'todo';
if (qaRoom) roomMap[qaRoom] = 'qa';

const results = [];
const joinedRooms = syncResp.rooms?.join || {};
const botMention = '@kb-bot:matrix.singll.net';

for (const [roomId, roomData] of Object.entries(joinedRooms)) {
  const botType = roomMap[roomId];
  if (!botType) continue;

  const events = roomData.timeline?.events || [];

  for (const event of events) {
    if (event.type !== 'm.room.message') continue;
    // 过滤 bot 自己的消息
    if (event.sender && event.sender.startsWith('@kb-bot:')) continue;
    // 去重：跳过已处理的事件
    if (staticData.processedEvents.includes(event.event_id)) continue;

    let body = (event.content?.body || '').trim();
    let rawMessage = body;

    // 检测提及触发
    if (body.includes(botMention)) {
      // 提取 mention 后的内容
      const mentionIndex = body.indexOf(botMention);
      body = body.substring(mentionIndex + botMention.length).trim();
      // 如果不以 ! 或 ！ 开头，自动添加
      if (body && !body.startsWith('!') && !body.startsWith('！')) {
        body = '!' + body;
      }
      rawMessage = body;
    }

    // 只处理以 ! 或 ！ 开头的指令
    if (!body.startsWith('!') && !body.startsWith('！')) continue;

    // 记录已处理的事件
    staticData.processedEvents.push(event.event_id);

    results.push({
      bot_type: botType,
      room_id: roomId,
      sender: event.sender,
      raw_message: rawMessage,
      event_id: event.event_id
    });
  }
}

// 只保留最近 200 个 event_id，避免内存无限增长
if (staticData.processedEvents.length > 200) {
  staticData.processedEvents = staticData.processedEvents.slice(-200);
}

return results.length > 0 ? results.map(r => ({ json: r })) : [];

const input = $input.first().json;
const botType = input.bot_type;
const rawMessage = input.raw_message;

// 移除开头的 ! 或 ！
const content = rawMessage.substring(1).trim();
const parts = content.split(/\s+/);
const cmd = parts[0].toLowerCase();
const args = parts.slice(1).join(' ');

let command = '';
let parsedArgs = {};

// === 全局指令（任何房间均可触发） ===
switch(cmd) {
  case '补录':
  case 'backfill': case 'bf':
    command = 'backfill';
    if (args) {
      const daysMatch = args.match(/(\d+)天/);
      if (daysMatch) {
        parsedArgs.days = parseInt(daysMatch[1]);
        parsedArgs.limit = 200;
      } else {
        parsedArgs.limit = parseInt(args) || 200;
      }
    } else {
      parsedArgs.limit = 200;
    }
    break;
  case '解析状态': case '解析进度':
  case 'parse-status': case 'ps':
    command = 'parse_status';
    break;
  case '帮助': case 'help': case 'h': case '?':
    command = 'help';
    break;
}

// === 房间特定指令 ===
if (!command) {
  if (botType === 'todo') {
    switch(cmd) {
      case '待办': case '列表': case '待办列表':
      case '查询': case '查看':
      case 'list': case 'ls': case 'show':
        command = 'list';
        break;
      case '今日': case '今天':
      case 'today':
        command = 'list';
        parsedArgs.filter = 'today';
        break;
      case '逾期':
      case 'overdue':
        command = 'list';
        parsedArgs.filter = 'overdue';
        break;
      case '新增': case '添加':
      case 'add': case 'new': case 'create':
        if (args) {
          command = 'add';
          let priority = 3;
          let dueDate = '';
          let remaining = args;
          for (let i = 0; i < 2; i++) {
            const pMatch = remaining.match(/^P(\d)\s+([\s\S]*)/);
            if (pMatch) { priority = parseInt(pMatch[1]); remaining = pMatch[2]; continue; }
            const dFull = remaining.match(/^D(\d{4}-\d{1,2}-\d{1,2})\s+([\s\S]*)/);
            if (dFull) { dueDate = dFull[1]; remaining = dFull[2]; continue; }
            const dShort = remaining.match(/^D(\d{1,2})\/(\d{1,2})\s+([\s\S]*)/);
            if (dShort) {
              const y = new Date().getFullYear();
              dueDate = `${y}-${dShort[1].padStart(2,'0')}-${dShort[2].padStart(2,'0')}`;
              remaining = dShort[3]; continue;
            }
            break;
          }
          parsedArgs.text = remaining.trim();
          parsedArgs.priority = priority;
          parsedArgs.dueDate = dueDate;
        }
        break;
      case '完成':
      case 'done': case 'complete': case 'finish':
        if (args) {
          command = 'done';
          parsedArgs.memo_name = `memos/${args}`;
        }
        break;
      case '删除':
      case 'delete': case 'del': case 'remove': case 'rm':
        if (args) {
          command = 'delete';
          parsedArgs.memo_name = `memos/${args}`;
        }
        break;
      case '修改':
      case 'modify': case 'edit': case 'update': {
        const modParts = args.split(/\s+/);
        if (modParts.length >= 2) {
          command = 'modify';
          parsedArgs.memo_name = `memos/${modParts[0]}`;
          parsedArgs.text = modParts.slice(1).join(' ');
        }
        break;
      }
    }
  } else if (botType === 'qa') {
    switch(cmd) {
      case '问':
      case 'ask': case 'question': case 'q':
        if (args) {
          command = 'ask';
          parsedArgs.question = args;
        }
        break;
      case '搜': case '搜索':
      case 'search': case 'find': case 's':
        if (args) {
          command = 'search';
          parsedArgs.keywords = args;
        }
        break;
    }
  }
}

if (!command) {
  command = 'unknown';
}

return [{
  json: {
    bot_type: botType,
    room_id: input.room_id,
    sender: input.sender,
    command: command,
    args: parsedArgs,
    raw_message: rawMessage
  }
}];

const input = $('解析指令').first().json;
const botType = input.bot_type;
const message = '❓ 未知指令，发送 !帮助 查看用法';
const html = '<p>❓ 未知指令，发送 <code>!帮助</code> 查看用法</p>';
return [{ json: { message, html, bot_type: botType } }];

const command = $('解析指令').first().json;
const response = $input.first().json;
const botType = command.bot_type;

let message = '';
let html = '';

// responseFormat: text 时，响应在 response.data 字段中为字符串
let hasError = false;
if (response.error) {
  hasError = true;
} else if (typeof response.data === 'string') {
  // 检查文本响应是否包含错误
  const text = response.data.toLowerCase();
  if (text.includes('error') || text.includes('failed') || text.includes('invalid')) {
    hasError = true;
  }
}

if (hasError) {
  const err = response.error ? (typeof response.error === 'object' ? (response.error.message || JSON.stringify(response.error)) : String(response.error)) : response.data || 'webhook调用失败';
  message = `❌ 补录任务启动失败: ${err}`;
  html = `<p>❌ 补录任务启动失败: ${err}</p>`;
} else {
  const limit = command.args.limit || 200;
  const days = command.args.days || 0;
  const daysInfo = days > 0 ? `最近 ${days} 天的` : '';
  message = `✅ 补录任务已启动，将从所有 RSS 源获取${daysInfo}最多 ${limit} 条文章。\n采集和解析完成后会分别发送通知。`;
  html = `<p>✅ 补录任务已启动，将从所有 RSS 源获取${daysInfo}最多 <b>${limit}</b> 条文章。</p><p><i>采集和解析完成后会分别发送通知。</i></p>`;
}

return [{ json: { message, html, bot_type: botType } }];

const command = $('解析指令').first().json;
const response = $input.first().json;
const action = command.command;
const filter = command.args.filter || '';
const botType = command.bot_type;

let message = '';
let html = '';

if (response.success === false || response.error) {
  message = `❌ 操作失败: ${response.error || '未知错误'}`;
  html = `<p>❌ 操作失败: ${response.error || '未知错误'}</p>`;
} else {
  switch(action) {
    case 'list': {
      let memos = response.memos || [];
      const now = new Date();
      const todayStr = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;

      if (filter === 'today') {
        memos = memos.filter(m => {
          const d = (m.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          return d && d[1] === todayStr;
        });
      } else if (filter === 'overdue') {
        memos = memos.filter(m => {
          const d = (m.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          return d && d[1] < todayStr;
        });
      }

      const filterLabel = filter === 'today' ? '今日到期' : filter === 'overdue' ? '逾期' : '待办列表';

      if (memos.length === 0) {
        const emptyMsg = filter === 'today' ? '今日没有到期事项' : filter === 'overdue' ? '没有逾期事项' : '当前没有待办事项';
        message = `📝 ${emptyMsg}`;
        html = `<p>📝 <i>${emptyMsg}</i></p>`;
      } else {
        memos.sort((a, b) => {
          const dA = (a.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          const dB = (b.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          const dateA = dA ? dA[1] : '9999-99-99';
          const dateB = dB ? dB[1] : '9999-99-99';
          const overA = dA && dA[1] < todayStr ? 0 : 1;
          const overB = dB && dB[1] < todayStr ? 0 : 1;
          if (overA !== overB) return overA - overB;
          if (dateA !== dateB) return dateA.localeCompare(dateB);
          const pA = parseInt((a.content?.match(/#P(\d)/) || [])[1] || '3');
          const pB = parseInt((b.content?.match(/#P(\d)/) || [])[1] || '3');
          return pA - pB;
        });

        const lines = [`📝 ${filterLabel} (${memos.length}项):`];
        html = `<h4>📝 ${filterLabel} (${memos.length}项)</h4>\n<ul>\n`;
        memos.forEach((memo, i) => {
          const content = memo.content || '';
          const text = content.replace(/#\S+/g, '').trim();
          const id = (memo.name || '').replace('memos/', '');
          const priority = (content.match(/#P(\d)/) || [])[1] || '3';
          const pEmoji = priority === '1' ? '🔴' : priority === '2' ? '🟡' : '⚪';
          const dueMatch = content.match(/#D:(\d{4})-(\d{2})-(\d{2})/);
          let dateStr = '';
          let htmlDate = '';
          if (dueMatch) {
            const isOverdue = `${dueMatch[1]}-${dueMatch[2]}-${dueMatch[3]}` < todayStr;
            const isToday = `${dueMatch[1]}-${dueMatch[2]}-${dueMatch[3]}` === todayStr;
            dateStr = isOverdue ? ` ⚠️${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}(逾期)` : isToday ? ` 📅今日` : ` 📅${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}`;
            htmlDate = isOverdue ? ` <b>⚠️${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}</b>` : isToday ? ` 📅今日` : ` 📅${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}`;
          }
          lines.push(`${pEmoji} ${i+1}. [#${id}] P${priority}${dateStr} ${text}`);
          html += `<li>${pEmoji} <code>#${id}</code> P${priority}${htmlDate} ${text}</li>\n`;
        });
        message = lines.join('\n');
        html += `</ul>`;
      }
      break;
    }
    case 'add': {
      let extra = '';
      if (command.args.dueDate) {
        const dp = command.args.dueDate.split('-');
        extra = ` (📅${parseInt(dp[1])}/${parseInt(dp[2])})`;
      }
      message = `➕ 已添加待办: ${command.args.text}${extra}`;
      html = `<p>➕ 已添加待办: <b>${command.args.text}</b>${extra}</p>`;
      break;
    }
    case 'done':
      message = `✅ 已完成: ${(command.args.memo_name || '').replace('memos/', '#')}`;
      html = `<p>✅ 已完成: <code>${(command.args.memo_name || '').replace('memos/', '#')}</code></p>`;
      break;
    case 'delete':
      message = `🗑️ 已删除: ${(command.args.memo_name || '').replace('memos/', '#')}`;
      html = `<p>🗑️ 已删除: <code>${(command.args.memo_name || '').replace('memos/', '#')}</code></p>`;
      break;
    case 'modify':
      message = `✏️ 已修改: ${command.args.text}`;
      html = `<p>✏️ 已修改: <b>${command.args.text}</b></p>`;
      break;
    default:
      message = `❓ 未知操作: ${action}`;
      html = `<p>❓ 未知操作: ${action}</p>`;
  }
}

return [{ json: { message, html, bot_type: botType } }];

const command = $('解析指令').first().json;
const response = $input.first().json;
const botType = command.bot_type;

let message = '';
let html = '';

if (response.success === false || response.error) {
  const errMsg = typeof response.error === 'object' ? (response.error.message || JSON.stringify(response.error)) : String(response.error || '未知错误');
  message = `❌ 操作失败: ${errMsg}`;
  html = `<p>❌ 操作失败: ${errMsg}</p>`;
} else if (response.message) {
  message = response.message;
  let h = response.message;
  // 转义 HTML 特殊字符
  h = h.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  // 粗体 **text**
  h = h.replace(/\*\*(.+?)\*\*/g, '<b>$1</b>');
  // 斜体 *text* (不匹配列表项 *   )
  h = h.replace(/(?<!\\)\*(?!\s{2,})(.+?)(?<!\\)\*/g, '<i>$1</i>');
  // 行内代码 `code`
  h = h.replace(/`([^`]+)`/g, '<code>$1</code>');
  // 知识库标题 📘
  h = h.replace(/^(📘[^\n]*)/m, '<h4>$1</h4>');
  // 搜索标题 🔍
  h = h.replace(/^(🔍[^\n]*)/m, '<h4>$1</h4>');
  // 旧兼容标题 🤖
  h = h.replace(/^(🤖[^\n]*)/m, '<h4>$1</h4>');
  // 问题行
  h = h.replace(/^(问题：[^\n]*)/m, '<p><i>$1</i></p>');
  // ## 小节标题
  h = h.replace(/^## (.+)$/gm, '<h5>$1</h5>');
  // 参考来源中的摘要行
  h = h.replace(/^   摘要：(.+)$/gm, '<blockquote>$1</blockquote>');
  // 数字列表项
  h = h.replace(/^(\d+)\. (.+)$/gm, '<li>$2</li>');
  // 列表项 *   text → <li>text</li>
  h = h.replace(/^\*\s{2,}(.+)$/gm, '<li>$1</li>');
  // 连续 <li> 包裹 <ol>
  h = h.replace(/(<li>.*?<\/li>\n?)+/gs, (match) => '<ol>' + match + '</ol>');
  // 换行转 <br>
  h = h.replace(/\n/g, '<br>');
  // 清理多余 <br> 在块级元素前后
  h = h.replace(/<br>(<\/?(?:h[1-6]|ol|ul|li|blockquote|p)>)/g, '$1');
  h = h.replace(/(<\/?(?:h[1-6]|ol|ul|li|blockquote|p)>)<br>/g, '$1');
  html = h;
} else {
  message = '✅ 操作成功';
  html = '<p>✅ 操作成功</p>';
}

return [{ json: { message, html, bot_type: botType } }];

const input = $input.first().json;
const botType = input.bot_type;
const message = input.message;
const html = input.html || null;

const roomMap = {
  'todo': 'todo',
  'qa': 'qa'
};

const room = roomMap[botType] || 'todo';

return [{ json: { room, message, html } }];

const command = $('解析指令').first().json;
const response = $input.first().json;
const botType = command.bot_type;

let message = '';
let html = '';

if (response.error) {
  message = '解析状态查询失败: ' + (typeof response.error === 'object' ? (response.error.message || JSON.stringify(response.error)) : String(response.error));
  html = '<p>' + message + '</p>';
} else {
  const datasets = response.datasets || [];
  const totalDocs = response.total_documents || 0;
  const totalParsed = response.total_parsed || 0;
  const totalUnparsed = response.total_unparsed || 0;
  const totalFailed = response.total_failed || 0;
  const totalRunning = response.total_running || 0;
  const pct = totalDocs > 0 ? Math.round(totalParsed / totalDocs * 100) : 0;

  const bar = '█'.repeat(Math.round(pct / 5)) + '░'.repeat(20 - Math.round(pct / 5));

  message = `📊 RAGFlow 解析状态\n${bar} ${pct}%\n总计: ${totalDocs} | 已解析: ${totalParsed} | 未解析: ${totalUnparsed} | 运行中: ${totalRunning} | 失败: ${totalFailed}`;
  html = `<h4>📊 RAGFlow 解析状态</h4>`;
  html += `<p><code>${bar}</code> <b>${pct}%</b></p>`;
  html += `<p>总计: ${totalDocs} | 已解析: ${totalParsed} | 未解析: ${totalUnparsed} | 运行中: ${totalRunning} | 失败: ${totalFailed}</p>`;

  if (datasets.length > 0) {
    html += '<table><tr><th>知识库</th><th>总数</th><th>已解析</th><th>未解析</th><th>进度</th></tr>';
    for (const ds of datasets) {
      const dsPct = ds.total > 0 ? Math.round(ds.parsed / ds.total * 100) : 0;
      const statusIcon = ds.unparsed > 0 ? '⏳' : ds.failed > 0 ? '⚠️' : '✅';
      html += `<tr><td>${statusIcon} ${ds.name}</td><td>${ds.total}</td><td>${ds.parsed}</td><td>${ds.unparsed}</td><td>${dsPct}%</td></tr>`;
      message += `\n${statusIcon} ${ds.name}: ${ds.parsed}/${ds.total} (${dsPct}%)`;
    }
    html += '</table>';
  }
}

return [{ json: { message, html, bot_type: botType } }];
